import boto3, json, time
_client = boto3.client('secretsmanager')
_cache = {}
def get_secret(name, ttl=300):
    hit = _cache.get(name)
    if hit and time.time() - hit[1] < ttl:
        return hit[0]
    val = json.loads(_client.get_secret_value(SecretId=name)['SecretString'])
    _cache[name] = (val, time.time())
    return val
STRIPE_KEY = get_secret('prod/stripe')['secret_key']
def handler(event, ctx):
    return charge(STRIPE_KEY, event)

import os
