import subprocess
from jsonschema import validate, ValidationError
SCHEMA = {'type': 'object', 'required': ['key'], 'properties': {'key': {'type': 'string', 'pattern': '^[a-zA-Z0-9_-]+\\.png$'}}}
def handler(event, context):
    rec = event['Records'][0]['s3']['object']
    try:
        validate(rec, SCHEMA)
    except ValidationError:
        return {'statusCode': 400, 'body': 'bad event'}
    subprocess.run(['convert', '/tmp/' + rec['key'], '/tmp/out.png'], shell=False, check=True)
    return {'statusCode': 200}
